import React, { useState, useMemo, useRef, useCallback } from 'react';
import { generateSpeech, decodeAudioData, audioBufferToWav } from '../services/geminiService';

// --- Types ---
interface Voice { id: string; name: string; apiId: string; description?: string; }

// --- CONSTANTS ---
// Generating ~100 distinct voices for Vietnamese
const generateVietnameseVoices = () => {
  const femaleNames = [
    'Mai', 'Lan', 'Cúc', 'Trúc', 'Hương', 'Thảo', 'Trang', 'Huyền', 'Linh', 'Ngọc', 
    'Tuyết', 'Hạnh', 'Vân', 'Nhung', 'Phượng', 'Thúy', 'Diễm', 'Kiều', 'Bích', 'Quỳnh',
    'Thu', 'Hằng', 'Nga', 'Yến', 'Oanh', 'Ly', 'My', 'Vy', 'Hà', 'Phương'
  ];
  const maleNames = [
    'Hùng', 'Dũng', 'Tuấn', 'Minh', 'Thắng', 'Nam', 'Việt', 'Đức', 'Trung', 'Hiếu',
    'Nghĩa', 'Quang', 'Hải', 'Sơn', 'Tùng', 'Lâm', 'Khánh', 'Hoàng', 'Thành', 'Vinh',
    'Bảo', 'Long', 'Phúc', 'Tâm', 'Huy', 'Cường', 'Bình', 'An', 'Kiên', 'Đạt'
  ];

  const regions = [
    { 
      code: 'bac', 
      name: 'Miền Bắc', 
      styles: [
        'Tin tức', 'Kể chuyện', 'Thuyết minh', 'Đối thoại', 
        'Review Công nghệ', 'Review Xe', 'Review Phim', 'Review Sách', 'Review Bất động sản'
      ] 
    },
    { 
      code: 'trung', 
      name: 'Miền Trung', 
      styles: [
        'Kể chuyện', 'Tâm sự', 'Đọc thơ', 'Dân ca', 
        'Review Chân thực', 'Vlog Đời sống', 'Review Du lịch'
      ] 
    },
    { 
      code: 'nam', 
      name: 'Miền Nam', 
      styles: [
        'Tin tức', 'Sôi động', 'Bán hàng', 'Vlog', 'Giải trí',
        'Review Ẩm thực', 'Review Mỹ phẩm', 'Review Thời trang', 'Unboxing', 'Review Quán xá'
      ] 
    }
  ];

  const voices: { female: Voice[], male: Voice[] } = { female: [], male: [] };

  // Mapping logic to Gemini Voices (5 available)
  // Kore: Female Balanced (Standard)
  // Zephyr: Female Soft (Gentle/Storytelling)
  // Puck: Male Deep (Standard/Storytelling)
  // Fenrir: Male Strong (Energetic/Sales)
  // Charon: Male Authoritative (News/Tech/Documentary)

  let fCount = 0;
  let mCount = 0;

  regions.forEach(reg => {
    reg.styles.forEach(style => {
        // --- Add Female Voice ---
        const fName = femaleNames[fCount % femaleNames.length];
        let fApiId = 'Kore'; // Default Balanced

        // Map specific styles to Soft voice
        if (
            style.includes('Kể chuyện') || 
            style.includes('Tâm sự') || 
            style.includes('Thơ') || 
            style.includes('Mỹ phẩm') || 
            style.includes('Ẩm thực') ||
            style.includes('Thời trang') ||
            style.includes('Vlog')
        ) {
            fApiId = 'Zephyr'; 
        }

        voices.female.push({
            id: `vi_f_${reg.code}_${fCount}`,
            name: `${fName} (${reg.name} - ${style})`,
            apiId: fApiId,
            description: `Giọng nữ ${reg.name}, phong cách ${style.toLowerCase()}.`
        });
        fCount++;

        // --- Add Male Voice ---
        const mName = maleNames[mCount % maleNames.length];
        let mApiId = 'Puck'; // Default Deep

        // Map specific styles to Authoritative/Deep voice
        if (
            style.includes('Tin tức') || 
            style.includes('Thuyết minh') || 
            style.includes('Công nghệ') || 
            style.includes('Xe') || 
            style.includes('Bất động sản') ||
            style.includes('Sách')
        ) {
            mApiId = 'Charon'; 
        }

        // Map specific styles to Energetic voice
        if (
            style.includes('Sôi động') || 
            style.includes('Bán hàng') || 
            style.includes('Giải trí') || 
            style.includes('Du lịch') || 
            style.includes('Unboxing') ||
            style.includes('Quán xá')
        ) {
            mApiId = 'Fenrir';
        }

        voices.male.push({
            id: `vi_m_${reg.code}_${mCount}`,
            name: `${mName} (${reg.name} - ${style})`,
            apiId: mApiId,
            description: `Giọng nam ${reg.name}, phong cách ${style.toLowerCase()}.`
        });
        mCount++;
    });
  });

  return voices;
};

const VI_VOICES = generateVietnameseVoices();

const VOICES_BY_LANGUAGE: Record<string, { female: Voice[], male: Voice[] }> = {
  'vi': VI_VOICES,
  'en': {
    female: [
      {id: 'en_us_1', name: 'Kore (US - Balanced)', apiId: 'Kore', description: 'American English, standard balanced tone.'}, 
      {id: 'en_us_2', name: 'Zephyr (US - Soft)', apiId: 'Zephyr', description: 'American English, soft and gentle.'}
    ],
    male: [
      {id: 'en_us_3', name: 'Puck (US - Deep)', apiId: 'Puck', description: 'American English, deep voice.'}, 
      {id: 'en_us_4', name: 'Fenrir (US - Strong)', apiId: 'Fenrir', description: 'American English, strong and energetic.'}, 
      {id: 'en_us_5', name: 'Charon (US - Authoritative)', apiId: 'Charon', description: 'American English, authoritative news style.'}
    ]
  }
};

// Helper to fill other languages with English voices as placeholders
['zh', 'es', 'fr', 'de', 'it', 'pt', 'ru', 'ja', 'ko', 'ar', 'hi', 'bn', 'id', 'tr', 'nl', 'pl', 'sv', 'no', 'da', 'fi', 'el', 'cs', 'hu', 'ro', 'th', 'he', 'uk', 'ms', 'fa', 'fil', 'af', 'bg', 'ca', 'hr', 'et', 'gl', 'is', 'lt', 'lv', 'mk', 'sk', 'sl', 'sr', 'sw', 'ur', 'gu', 'kn', 'ml', 'mr', 'ta', 'te', 'jv'].forEach(lang => {
    VOICES_BY_LANGUAGE[lang] = VOICES_BY_LANGUAGE['en'];
});

const BANNED_WORDS: string[] = ['phản động', 'khiêu dâm', 'bạo lực', 'giết người', 'ma túy', 'cờ bạc'];
const TOKEN_PER_CHAR = 0.25;
const PRICE_PER_1K_TOKENS = 0.000;
const SCENARIOS = [
  { name: "Lời chào", text: "Xin chào, tôi là trợ lý ảo của bạn. Rất vui được gặp bạn!" },
  { name: "Kể chuyện", text: "Ngày xửa ngày xưa, ở một vương quốc nọ, có một nàng công chúa xinh đẹp..." },
  { name: "Tin tức", text: "Dự báo thời tiết hôm nay trời nắng đẹp, nhiệt độ khoảng 25 độ C." },
  { name: "Marketing", text: "Sản phẩm mới ra mắt với nhiều tính năng vượt trội, hãy đặt mua ngay hôm nay!" }
];

// --- UI Atom Components ---

const Label: React.FC<{ children: React.ReactNode; htmlFor?: string }> = ({ children, htmlFor }) => (
  <label htmlFor={htmlFor} className="block text-sm font-medium text-gray-700 mb-1">{children}</label>
);

const Field: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <div className="mb-4">{children}</div>
);

const Select: React.FC<React.SelectHTMLAttributes<HTMLSelectElement>> = (props) => (
  <select
    {...props}
    className={
      "w-full rounded-md border border-gray-300 bg-white p-2 text-sm shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 " +
      (props.className ?? "")
    }
  />
);

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  loading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ loading, ...rest }) => (
  <button
    {...rest}
    className={
      "inline-flex items-center justify-center rounded-lg px-4 py-2 text-sm font-semibold shadow-sm transition-all active:scale-[.98] disabled:opacity-50 " +
      "bg-indigo-600 text-white hover:bg-indigo-700 disabled:bg-indigo-300 " +
      (rest.className ?? "")
    }
  >
    {loading ? (
      <>
        <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
        Generating...
      </>
    ) : rest.children}
  </button>
);

interface CardProps {
  children: React.ReactNode;
  title?: string;
  desc?: string;
}

const Card: React.FC<CardProps> = ({ children, title, desc }) => (
  <div className="rounded-xl border border-gray-200 bg-white p-4 shadow-sm h-full flex flex-col">
    {title && (
      <div className="mb-3">
        <h3 className="text-base font-semibold">{title}</h3>
        {desc && <p className="text-xs text-gray-500">{desc}</p>}
      </div>
    )}
    <div className="flex-grow">{children}</div>
  </div>
);

// --- Component ---

export const TextToSpeech: React.FC = () => {
  const [text, setText] = useState("");
  const [language, setLanguage] = useState('vi');
  const [voiceId, setVoiceId] = useState<string>(VOICES_BY_LANGUAGE['vi'].female[0].id);
  const [speed, setSpeed] = useState(1.0);
  const [pitch, setPitch] = useState(0);
  const [isSSML, setIsSSML] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const charCount = text.length;
  const estTokens = useMemo(() => charCount * TOKEN_PER_CHAR, [charCount]);
  const estCost = useMemo(() => (estTokens / 1000) * PRICE_PER_1K_TOKENS, [estTokens]);

  const violations = useMemo(() => {
    const lowerText = text.toLowerCase();
    return BANNED_WORDS.filter(word => lowerText.includes(word));
  }, [text]);

  const selectedVoice = useMemo<Voice>(() => {
    const langVoices = VOICES_BY_LANGUAGE[language];
    const allVoices = [
      ...langVoices.female, 
      ...langVoices.male
    ];
    return allVoices.find((v: any) => v.id === voiceId) || allVoices[0];
  }, [voiceId, language]);

  // Helper to create WAV blob
  const createWavBlob = async (base64Audio: string): Promise<Blob> => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    try {
        const audioBuffer = await decodeAudioData(base64Audio, ctx);
        const blob = audioBufferToWav(audioBuffer);
        return blob;
    } finally {
        ctx.close();
    }
  };

  const handleSynthesize = useCallback(async () => {
    if (!text.trim()) {
      setError("Please enter some text to synthesize.");
      return;
    }
    if (violations.length > 0) {
      setError(`Content contains banned words: ${violations.join(", ")}`);
      return;
    }

    setError(null);
    setLoading(true);
    setAudioUrl(null);

    try {
      const base64Audio = await generateSpeech({
        text,
        voiceId: selectedVoice.apiId,
        speed: speed,
        pitch: pitch,
        isSSML
      });

      if (!base64Audio) throw new Error("No audio returned");

      const wavBlob = await createWavBlob(base64Audio);
      const url = URL.createObjectURL(wavBlob);
      setAudioUrl(url);

      // Wait a bit for the audio element to be ready with the new source
      setTimeout(() => {
        if (audioRef.current) {
            audioRef.current.playbackRate = speed; // Apply speed client-side
            audioRef.current.play().catch(console.error);
        }
      }, 100);

    } catch (e: any) {
      console.error(e);
      setError(e.message || "An error occurred while generating speech.");
    } finally {
      setLoading(false);
    }
  }, [text, selectedVoice, speed, pitch, isSSML, violations]);

  const handleDownload = useCallback(() => {
    if (!audioUrl) return;
    const a = document.createElement("a");
    a.href = audioUrl;
    a.download = `tts_${selectedVoice.name.replace(/\s+/g, '_')}_${new Date().toISOString().slice(0,10)}.wav`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  }, [audioUrl, selectedVoice]);

  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newLang = e.target.value;
    setLanguage(newLang);
    // Reset voice selection to the first available voice of the new language
    const newLangVoices = VOICES_BY_LANGUAGE[newLang];
    const firstVoice = newLangVoices.female[0] || newLangVoices.male[0];
    if(firstVoice) {
      setVoiceId(firstVoice.id);
    }
  };

  const langVoices = VOICES_BY_LANGUAGE[language];
  const { male: maleVoices, female: femaleVoices } = langVoices;

  return (
    <div className="mx-auto max-w-7xl space-y-4 p-4 font-sans h-full overflow-y-auto custom-scrollbar">
      <header className="text-center">
        <h1 className="text-3xl font-bold tracking-tight text-gray-900 sm:text-4xl">AI Voice Studio</h1>
        <p className="mt-2 text-sm text-gray-600">Powered by Google Gemini. Kho giọng đọc đa dạng 3 miền Bắc - Trung - Nam.</p>
      </header>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
        <Card title="Cấu hình" desc="Chọn ngôn ngữ, giọng đọc và tham số">
          <Field>
            <Label htmlFor="lang-select">Ngôn ngữ (Language)</Label>
            <Select id="lang-select" value={language} onChange={handleLanguageChange}>
              <option value="vi">Tiếng Việt</option>
              <option value="en">English</option>
              <option value="zh">中文 (Chinese)</option>
              <option value="es">Español (Spanish)</option>
              <option value="fr">Français (French)</option>
              <option value="de">Deutsch (German)</option>
              <option value="ja">日本語 (Japanese)</option>
              <option value="ko">한국어 (Korean)</option>
              <option value="th">ไทย (Thai)</option>
              {/* Added basic list, extended supported in logic */}
            </Select>
          </Field>

          <Field>
            <Label htmlFor="voice-select">Giọng đọc (Voice)</Label>
            <Select
              id="voice-select"
              value={voiceId}
              onChange={(e) => setVoiceId(e.target.value)}
            >
              {femaleVoices.length > 0 && (
                <optgroup label="Giọng Nữ (Female)">
                  {femaleVoices.map((voice: any) => (
                    <option key={voice.id} value={voice.id}>
                      {voice.name}
                    </option>
                  ))}
                </optgroup>
              )}
              {maleVoices.length > 0 && (
                <optgroup label="Giọng Nam (Male)">
                  {maleVoices.map((voice: any) => (
                    <option key={voice.id} value={voice.id}>
                      {voice.name}
                    </option>
                  ))}
                </optgroup>
              )}
            </Select>
            {selectedVoice && (
              <div className="mt-2 p-2 bg-indigo-50 border border-indigo-100 rounded text-xs text-indigo-800">
                {selectedVoice.description}
              </div>
            )}
          </Field>

          <Field>
            <Label htmlFor="speed-range">Tốc độ (Speed): {speed.toFixed(2)}x</Label>
            <input id="speed-range" type="range" min={0.5} max={2} step={0.1} value={speed} onChange={e => setSpeed(parseFloat(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer" disabled={isSSML}/>
          </Field>
          {/* Pitch is purely decorative for now as client-side pitch shift is complex without lib, but kept for UI fidelity */}
          <Field>
            <Label htmlFor="pitch-range">Cao độ (Pitch): {pitch} (Mặc định)</Label>
            <input id="pitch-range" type="range" min={-5} max={5} step={1} value={pitch} onChange={e => setPitch(parseFloat(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer" disabled={true} title="Tính năng đang cập nhật"/>
          </Field>
          <div className="flex items-center gap-2 mt-4">
            <input id="ssml-checkbox" type="checkbox" checked={isSSML} onChange={e => setIsSSML(e.target.checked)} className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"/>
            <label htmlFor="ssml-checkbox" className="text-sm font-medium text-gray-700">Chế độ SSML (Nâng cao)</label>
          </div>
           {isSSML && <p className="mt-1 text-xs text-indigo-600">Speed và Pitch sẽ bị vô hiệu hóa trong chế độ SSML.</p>}
        </Card>

        <Card title="Nội dung" desc="Nhập văn bản hoặc SSML">
          <textarea
            className="h-64 w-full resize-none rounded-lg border border-gray-300 p-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 font-mono leading-relaxed"
            placeholder={isSSML ? '<speak>Xin chào <break time="500ms"/> mọi người!</speak>' : "Nhập văn bản cần đọc tại đây..."}
            value={text}
            onChange={(e) => setText(e.target.value)}
          />
          <div className="mt-2 flex items-center justify-between text-xs text-gray-500">
            <span>Ký tự: {charCount.toLocaleString()}</span>
            <span>Ước tính: ~${estCost.toFixed(6)}</span>
          </div>
          {violations.length > 0 && (
            <p className="mt-2 text-xs text-red-600 font-medium">Cảnh báo: Nội dung chứa từ khóa cấm - {violations.join(", ")}</p>
          )}
        </Card>

        <Card title="Kết quả" desc="Nghe thử và tải về">
          <div className="flex flex-col gap-3">
            <Button onClick={handleSynthesize} disabled={loading || !text.trim()} loading={loading} className="w-full py-3">
                Đọc Ngay (Generate)
            </Button>

            {error && <div className="p-3 bg-red-50 border border-red-100 rounded text-sm text-red-600">{error}</div>}

            <div className="mt-2 p-4 bg-gray-50 rounded-xl border border-gray-200 flex flex-col items-center justify-center min-h-[120px]">
                {audioUrl ? (
                    <div className="w-full space-y-3">
                        <audio ref={audioRef} src={audioUrl} controls className="w-full" />
                        <Button onClick={handleDownload} className="w-full bg-green-600 hover:bg-green-700">
                            Tải xuống WAV
                        </Button>
                    </div>
                ) : (
                    <div className="text-gray-400 text-sm text-center">
                        Bấm "Đọc Ngay" để tạo file âm thanh
                    </div>
                )}
            </div>

            <div className="mt-4 p-3 bg-indigo-50 rounded-lg text-xs text-indigo-800 border border-indigo-100">
                <p className="font-bold mb-1">Mẹo SSML:</p>
                <code className="block">{`<break time="500ms"/>`} - Ngắt nghỉ</code>
                <code className="block">{`<emphasis>text</emphasis>`} - Nhấn mạnh</code>
            </div>
          </div>
        </Card>
      </div>

      <Card title="Kịch bản mẫu (Quick Scenarios)">
        <div className="grid grid-cols-1 gap-2 md:grid-cols-2 lg:grid-cols-4">
          {SCENARIOS.map((p) => (
            <button
              key={p.name}
              onClick={() => setText(p.text)}
              className="rounded-lg border border-gray-200 p-3 text-left text-sm transition hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-indigo-500 hover:shadow-sm"
            >
              <div className="font-bold text-gray-800 mb-1">{p.name}</div>
              <div className="text-gray-600 line-clamp-2 text-xs">{p.text}</div>
            </button>
          ))}
        </div>
      </Card>
    </div>
  );
}

