import React, { useState, useEffect } from 'react';
import { Copy, Check, Sparkles, RefreshCw, Info, FileText, ClipboardList, Smartphone, Monitor, Square, LayoutTemplate, Edit3, PenTool, Layers, Lightbulb, MessageSquare, ScanEye, Video, Clapperboard, Film, User, Package, AlertCircle, Tv, Layout, ListChecks, GitCompare, Footprints, Activity, Mic, Volume2, Banana, Upload, Image as ImageIcon, Wand2, X, Loader2, Bot, Quote, Palette, Compass, Scale, List, BookOpen, ArrowUpLeft, ArrowUpRight, ArrowDownLeft, ArrowDownRight, AlignCenter, ArrowUp, ArrowDown, ArrowLeft, ArrowRight, CheckCircle as CheckCircleIcon, MonitorPlay, Settings, Maximize2, CheckCircle, Clock } from 'lucide-react';
import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ensureApiKeySelected } from '../services/geminiService';
import { UploadBox } from './UploadBox';
import { ImageAsset } from '../types';
import { fileToBase64, getMimeType } from '../utils';

// --- DATA: QUOTES DATABASE ---
const QUOTES_DATA = [
    { text: "Cách duy nhất để làm nên sự nghiệp vĩ đại là yêu lấy những gì bạn đang làm.", author: "Steve Jobs", category: "success", tag: "Thành công" },
