// --- SUB-COMPONENT: PromptCard (Dùng cho Tab 1) ---
interface PromptCardProps {
  item: any;
  topic: string;
}

const PromptCard: React.FC<PromptCardProps> = ({ item, topic }) => {
  const [copiedPrompt, setCopiedPrompt] = useState(false);
  const [copiedCaption, setCopiedCaption] = useState(false);
  const [caption, setCaption] = useState('');
  const [isGeneratingCaption, setIsGeneratingCaption] = useState(false);
  const [promptContent, setPromptContent] = useState(item.prompt);

  useEffect(() => {
    setPromptContent(item.prompt);
    setCaption(''); // Reset caption khi prompt thay đổi
    setCopiedPrompt(false); // Reset copy state when content changes
  }, [item.prompt]);

  // Hàm tạo Caption giả lập (Client-side template)
  const generateCaption = async () => {
    setIsGeneratingCaption(true);

    // Use Gemini for caption generation as well for better variety
    try {
        await ensureApiKeySelected();
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Viết một caption TikTok ngắn, viral, hấp dẫn cho chủ đề: "${topic}".
        Nội dung cụ thể của phần này là: "${item.title}".
        Yêu cầu:
        - Dùng icon sinh động.
        - Giọng điệu phù hợp (gây tò mò, hoặc cảnh báo, hoặc chia sẻ).
        - Kèm 5 hashtag liên quan.
        - Ngôn ngữ: Tiếng Việt.`;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt
        });

        setCaption(response.text || "Không thể tạo caption.");
    } catch (e) {
        // Fallback to template if API fails
        const safeTopic = topic || "vấn đề này";
        const cleanTopicHash = safeTopic.replace(/\s+/g, '').toLowerCase();
        let generatedText = `Chia sẻ kiến thức về ${safeTopic}. Follow để biết thêm chi tiết! #${cleanTopicHash}`;
        setCaption(generatedText);
    } finally {
        setIsGeneratingCaption(false);
    }
  };

  const handleCopyText = (text: string, type: 'prompt' | 'caption') => {
    navigator.clipboard.writeText(text);
    if (type === 'prompt') {
        setCopiedPrompt(true);
        // Removed setTimeout to keep the "Copied" state persistent
    } else {
        setCopiedCaption(true);
        setTimeout(() => setCopiedCaption(false), 2000);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-md hover:shadow-lg transition-all duration-300 border border-slate-200 overflow-hidden flex flex-col h-full group">
      <div className="p-5 flex-grow flex flex-col">
        {/* Header Card */}
        <div className="flex items-center justify-between mb-3">
          <span className="text-xs font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded uppercase tracking-wider">
            Phần {item.id}
          </span>
          <span className="text-xs text-slate-400 font-mono flex items-center gap-1">
             <Edit3 size={12} /> Sửa nội dung
          </span>
        </div>
        <h3 className="font-bold text-slate-800 text-lg mb-3 leading-tight">{item.title}</h3>

        {/* SAFE ZONE NOTE (New Feature) */}
        {item.posting_advice && (
            <div className="mb-4 bg-orange-50 border border-orange-100 rounded-lg p-3">
                <div className="flex items-start gap-2">
                    <ScanEye size={16} className="text-orange-600 mt-0.5 shrink-0" />
                    <div>
                        <span className="text-[10px] font-bold text-orange-700 uppercase block mb-0.5">Lưu ý Safe-Zone TikTok:</span>
                        <p className="text-xs text-orange-800 leading-snug">{item.posting_advice}</p>
                    </div>
                </div>
            </div>
        )}

        {/* PROMPT AREA */}
        <div className="mb-4">
          <label className="text-[10px] uppercase font-bold text-slate-400 mb-1 block">Prompt tạo ảnh:</label>
          <textarea
            value={promptContent}
            onChange={(e) => setPromptContent(e.target.value)}
            className="w-full bg-slate-50 p-3 rounded-lg border border-slate-200 font-mono text-xs text-slate-600 leading-relaxed h-24 overflow-y-auto custom-scrollbar focus:ring-2 focus:ring-blue-200 outline-none resize-none transition-all hover:bg-white"
          />
          <button 
            onClick={() => handleCopyText(promptContent, 'prompt')}
            className={`mt-2 w-full py-1.5 rounded text-xs font-medium border flex items-center justify-center gap-1 transition-all ${copiedPrompt ? 'bg-green-50 text-green-600 border-green-200' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
          >
            {copiedPrompt ? <Check size={12}/> : <Copy size={12}/>} {copiedPrompt ? 'Đã copy Prompt' : 'Copy Prompt'}
          </button>
        </div>

        {/* CAPTION AREA (NEW) */}
        {(caption || isGeneratingCaption) && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
             <div className="flex items-center gap-2 mb-1">
                <label className="text-[10px] uppercase font-bold text-pink-500 block">Caption TikTok:</label>
                {isGeneratingCaption && <RefreshCw size={10} className="animate-spin text-pink-500"/>}
             </div>

             <textarea
                value={caption}
                readOnly
                className="w-full bg-pink-50/50 p-3 rounded-lg border border-pink-100 font-sans text-sm text-slate-700 leading-relaxed h-32 overflow-y-auto custom-scrollbar focus:ring-2 focus:ring-pink-200 outline-none resize-none"
                placeholder="Đang viết caption..."
             />
             <button 
                onClick={() => handleCopyText(caption, 'caption')}
                disabled={!caption}
                className={`mt-2 w-full py-1.5 rounded text-xs font-medium border flex items-center justify-center gap-1 transition-all ${copiedCaption ? 'bg-green-50 text-green-600 border-green-200' : 'bg-white text-pink-600 border-pink-200 hover:bg-pink-50'}`}
              >
                {copiedCaption ? <Check size={12}/> : <Copy size={12}/>} {copiedCaption ? 'Đã copy Caption' : 'Copy Caption'}
              </button>
          </div>
        )}
      </div>

      {/* Footer Buttons */}
      <div className="p-3 bg-slate-50 border-t border-slate-100">
        <button
          onClick={generateCaption}
          className="w-full py-2.5 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-all bg-gradient-to-r from-slate-800 to-slate-700 text-white hover:shadow-md transform hover:-translate-y-0.5 active:translate-y-0"
        >
          {isGeneratingCaption ? <RefreshCw className="animate-spin" size={16} /> : <MessageSquare size={16} />}
          {caption ? 'Viết lại Caption khác' : 'Gợi ý Caption TikTok'}
        </button>
      </div>
    </div>
  );
};

