import { AdCreator } from './components/AdCreator';
import { ContentGeniusAI } from './components/ContentGeniusAI';
import { TextToSpeech } from './components/TextToSpeech';
import { PromptBuilder } from './components/PromptBuilder';
import { MarketingAI } from './components/MarketingAI';

const App: React.FC = () => {
  // Tabs: 'studio' | 'remove_bg' | 'ad_creator' | 'content_genius' | 'text_to_speech' | 'prompt_builder' | 'marketing_ai'
  const [activeTab, setActiveTab] = useState<'studio' | 'remove_bg' | 'ad_creator' | 'content_genius' | 'text_to_speech' | 'prompt_builder' | 'marketing_ai'>('studio');

  // --- Fashion Studio State ---
  const [personImage, setPersonImage] = useState<ProcessedImage | null>(null);
  const [productImage, setProductImage] = useState<ProcessedImage | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);

  const [selectedOutfit, setSelectedOutfit] = useState<OptionItem>(OUTFITS[0]);
  const [selectedPose, setSelectedPose] = useState<OptionItem>(POSES[0]);
  const [selectedBackdrop, setSelectedBackdrop] = useState<OptionItem>(BACKDROPS[0]);
  const [selectedExpression, setSelectedExpression] = useState<OptionItem>(EXPRESSIONS[0]);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState<OptionItem>(ASPECT_RATIOS[0]);

  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  const processFile = (file: File): Promise<ProcessedImage> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        if (event.target?.result) {
            img.src = event.target.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const MAX_WIDTH = 1024; 
              // Scale down if too large to save tokens/bandwidth
              const scaleSize = MAX_WIDTH / Math.max(img.width, MAX_WIDTH);
              canvas.width = img.width * scaleSize;
              canvas.height = img.height * scaleSize;
              const ctx = canvas.getContext('2d');
              if (ctx) {
                  ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                  const dataUrl = canvas.toDataURL(file.type);
                  resolve({
                    preview: dataUrl,
                    base64: dataUrl.split(',')[1],
                    mimeType: file.type
                  });
              } else {
                  reject(new Error("Canvas context failed"));
              }
            };
            img.onerror = (e) => reject(e);
        }
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'person' | 'product') => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setError('');
      const processed = await processFile(file);
      if (type === 'person') {
        setPersonImage(processed);
      } else {
        setProductImage(processed);
      }
      setResultImage(null);
    } catch (err) {
      console.error(err);
      setError('Lỗi xử lý ảnh. Vui lòng thử file khác.');
    }
  };

  const handleGenerate = async () => {
    if (!personImage || !productImage) {
      setError('Vui lòng tải lên cả ảnh người mẫu và ảnh sản phẩm.');
      return;
    }

    setIsGenerating(true);
    setError('');
    setResultImage(null);
    setStatusMessage('Đang phân tích...');

    try {
      // Simulate steps for better UX
      setTimeout(() => setStatusMessage('Đang xử lý ánh sáng...'), 2000);

      const result = await generateCompositeImage({
          personImage,
          productImage,
          outfit: selectedOutfit,
          pose: selectedPose,
          backdrop: selectedBackdrop,
          expression: selectedExpression,
          aspectRatio: selectedAspectRatio
      });

      setResultImage(result);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Tạo ảnh thất bại. Vui lòng thử lại.');
    } finally {
      setIsGenerating(false);
      setStatusMessage('');
    }
  };

  const handleReset = () => {
    setPersonImage(null);
    setProductImage(null);
    setResultImage(null);
    setError('');
    setSelectedOutfit(OUTFITS[0]);
    setSelectedPose(POSES[0]);
    setSelectedBackdrop(BACKDROPS[0]);
    setSelectedExpression(EXPRESSIONS[0]);
    setSelectedAspectRatio(ASPECT_RATIOS[0]);
  };

  const downloadImage = () => {
    if (resultImage) {
      const link = document.createElement('a');
      link.href = resultImage;
      link.download = `studio-gen-${selectedBackdrop.id}-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="h-screen bg-gradient-to-br from-indigo-50 via-white to-purple-50 font-sans text-gray-800 p-2 md:p-4 overflow-hidden flex flex-col">
      <div className="max-w-[1920px] w-full mx-auto bg-white/90 backdrop-blur-xl rounded-[1.5rem] shadow-2xl border border-white/50 flex flex-col h-full overflow-hidden">

        {/* Compact Header */}
        <div className="flex-none bg-gradient-to-r from-violet-600 to-indigo-600 px-6 py-3 text-white flex flex-col md:flex-row items-center justify-between gap-4 shadow-md z-20">
            <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-lg"><Sparkles className="text-yellow-300 w-5 h-5" /></div>
                <h1 className="text-xl font-extrabold tracking-tight">AI Fashion Studio</h1>
            </div>

            {/* Navigation Tabs - Scrollable on mobile */}
            <div className="flex gap-1 overflow-x-auto w-full md:w-auto pb-1 md:pb-0 custom-scrollbar">
                {[
                  { id: 'studio', label: 'Ghép Ảnh', icon: Sparkles },
                  { id: 'ad_creator', label: 'Poster QC', icon: Megaphone },
                  { id: 'marketing_ai', label: 'Marketing AI', icon: Camera },
                  { id: 'remove_bg', label: 'Tách Nền', icon: Eraser },
                  { id: 'content_genius', label: 'Content', icon: PenTool },
                  { id: 'text_to_speech', label: 'Giọng Đọc', icon: Mic },
                  { id: 'prompt_builder', label: 'Prompt AI', icon: Lightbulb }
                ].map(tab => (
                   <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`px-3 py-1.5 rounded-lg text-sm font-bold flex items-center gap-2 transition-all whitespace-nowrap
                    ${activeTab === tab.id 
                        ? 'bg-white text-indigo-700 shadow-sm' 
                        : 'text-white/80 hover:bg-white/10'}`}
                >
                    <tab.icon size={16} />
                    {tab.label}
                </button>
                ))}
            </div>
        </div>

        {/* --- MAIN CONTENT AREA --- */}
        <div className="flex-1 overflow-hidden relative bg-white">

            {/* TAB: Fashion Studio - 3 Column Layout */}
            {activeTab === 'studio' && (
              <div className="h-full grid grid-cols-1 lg:grid-cols-12 divide-y lg:divide-y-0 lg:divide-x divide-gray-200">

                  {/* COLUMN 1: UPLOADS (Left - 3 cols) */}
                  <div className="lg:col-span-3 p-4 flex flex-col gap-4 overflow-y-auto custom-scrollbar bg-slate-50/50">
                      <div className="flex items-center gap-2 mb-1">
                          <span className="bg-violet-100 text-violet-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">1</span>
                          <h3 className="font-bold text-gray-700 text-sm uppercase">Đầu Vào</h3>
                      </div>

                      <div className="space-y-4">
                        <ImageUploader 
                            label="Ảnh Người Mẫu" 
                            icon={<User size={14} className="text-violet-600" />}
                            image={personImage}
                            onUpload={(e) => handleFileUpload(e, 'person')}
                            onRemove={() => setPersonImage(null)}
                            colorClass="text-violet-600"
                            bgColorClass="bg-violet-50"
                            borderColorClass="border-violet-400"
                            heightClass="h-48"
                        />
                        <ImageUploader 
                            label="Ảnh Sản Phẩm" 
                            icon={<Box size={14} className="text-pink-600" />}
                            image={productImage}
                            onUpload={(e) => handleFileUpload(e, 'product')}
                            onRemove={() => setProductImage(null)}
                            colorClass="text-pink-600"
                            bgColorClass="bg-pink-50"
                            borderColorClass="border-pink-400"
                            heightClass="h-48"
                        />
                        {/* Error Message Small */}
                        {error && (
                          <div className="flex items-start gap-2 text-red-700 bg-red-50 p-3 rounded-lg border border-red-100 text-xs">
                              <AlertCircle size={14} className="shrink-0 mt-0.5" />
                              <span className="font-medium leading-tight">{error}</span>
                          </div>
                        )}
                      </div>
                  </div>

                  {/* COLUMN 2: CONFIG (Center - 5 cols) */}
                  <div className="lg:col-span-5 p-4 overflow-y-auto custom-scrollbar bg-white">
                      <div className="flex items-center gap-2 mb-4 sticky top-0 bg-white z-10 py-1">
                          <span className="bg-blue-100 text-blue-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">2</span>
                          <h3 className="font-bold text-gray-700 text-sm uppercase">Cấu Hình Studio</h3>
                      </div>

                      <div className="space-y-6">
                          {/* Grid for Options */}
                          <div className="grid grid-cols-2 gap-4">
                              <div className="space-y-2">
                                  <label className="flex items-center gap-1.5 font-bold text-gray-600 text-xs uppercase"><Shirt size={14}/> Trang phục</label>
                                  <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                      {OUTFITS.map((item) => (
                                          <div key={item.id} onClick={() => setSelectedOutfit(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedOutfit.id === item.id ? 'border-teal-500 bg-teal-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                              <div className="font-semibold">{item.label}</div>
                                          </div>
                                      ))}
                                  </div>
                              </div>

                              <div className="space-y-2">
                                  <label className="flex items-center gap-1.5 font-bold text-gray-600 text-xs uppercase"><Hand size={14}/> Dáng tay</label>
                                  <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                      {POSES.map((item) => (
                                          <div key={item.id} onClick={() => setSelectedPose(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedPose.id === item.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                              <div className="font-semibold">{item.label}</div>
                                          </div>
                                      ))}
                                  </div>
                              </div>

                              <div className="space-y-2">
                                  <label className="flex items-center gap-1.5 font-bold text-gray-600 text-xs uppercase"><Smile size={14}/> Biểu cảm</label>
                                  <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                      {EXPRESSIONS.map((item) => (
                                          <div key={item.id} onClick={() => setSelectedExpression(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedExpression.id === item.id ? 'border-amber-500 bg-amber-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                              <div className="font-semibold">{item.label}</div>
                                          </div>
                                      ))}
                                  </div>
                              </div>

                              <div className="space-y-2">
                                  <label className="flex items-center gap-1.5 font-bold text-gray-600 text-xs uppercase"><Crop size={14}/> Tỷ lệ</label>
                                  <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                      {ASPECT_RATIOS.map((item) => (
                                          <div key={item.id} onClick={() => setSelectedAspectRatio(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedAspectRatio.id === item.id ? 'border-emerald-500 bg-emerald-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                              <div className="font-semibold">{item.label}</div>
                                          </div>
                                      ))}
                                  </div>
                              </div>
                          </div>

                          {/* Backdrops - Full Width */}
                          <div className="space-y-2">
                              <label className="flex items-center gap-1.5 font-bold text-gray-600 text-xs uppercase"><Layers size={14}/> Bối cảnh / Nền</label>
                              <div className="grid grid-cols-2 gap-2 max-h-60 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-2">
                                  {BACKDROPS.map((item) => (
                                      <div key={item.id} onClick={() => setSelectedBackdrop(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all h-full ${selectedBackdrop.id === item.id ? 'border-blue-500 bg-blue-50 shadow-sm' : 'border-gray-100 hover:bg-gray-50'}`}>
                                          <div className="font-semibold text-gray-800">{item.label}</div>
                                          <div className="text-gray-500 text-[10px] line-clamp-2 mt-0.5">{item.desc}</div>
                                      </div>
                                  ))}
                              </div>
                          </div>
                      </div>
                  </div>

                  {/* COLUMN 3: RESULT (Right - 4 cols) */}
                  <div className="lg:col-span-4 p-4 flex flex-col gap-4 bg-slate-50/30">
                      <div className="flex items-center gap-2 mb-1">
                          <span className="bg-indigo-100 text-indigo-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">3</span>
                          <h3 className="font-bold text-gray-700 text-sm uppercase">Kết Quả</h3>
                      </div>

                      <button
                        onClick={handleGenerate}
                        disabled={!personImage || !productImage || isGenerating}
                        className={`
                        w-full py-3 rounded-xl text-sm font-bold text-white shadow-lg transition-all transform
                        ${(!personImage || !productImage) 
                            ? 'bg-gray-300 cursor-not-allowed' 
                            : isGenerating 
                            ? 'bg-gray-800 cursor-wait' 
                            : 'bg-gradient-to-r from-violet-600 to-indigo-600 hover:scale-[1.02] active:scale-95'}
                        `}
                    >
                        <div className="flex items-center justify-center gap-2">
                        {isGenerating ? <RefreshCw className="animate-spin" size={18} /> : <Sparkles size={18} />}
                        {isGenerating ? statusMessage || 'Đang xử lý...' : 'GHÉP ẢNH NGAY'}
                        </div>
                    </button>

                    {/* Result Area */}
                    <div className="flex-1 bg-gray-200/50 rounded-2xl border-2 border-dashed border-gray-300 flex flex-col items-center justify-center relative overflow-hidden group min-h-[300px]">
                        {resultImage ? (
                            <>
                            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10 pointer-events-none"></div>
                            <img src={resultImage} alt="Kết Quả" className="w-full h-full object-contain p-2 z-10" />
                            <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-2 z-20 px-4">
                                <button onClick={downloadImage} className="bg-white/90 backdrop-blur text-gray-900 px-4 py-2 rounded-full text-xs font-bold flex items-center gap-1 shadow-lg hover:bg-white hover:scale-105 transition-all">
                                    <Download size={14} /> Tải Về
                                </button>
                                <button onClick={handleReset} className="bg-gray-900/90 backdrop-blur text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-1 shadow-lg hover:bg-black hover:scale-105 transition-all">
                                    <RefreshCw size={14} /> Thử Lại
                                </button>
                            </div>
                            </>
                        ) : (
                            <div className="text-center text-gray-400 p-6">
                                <ImageIcon size={32} className="mx-auto mb-2 opacity-50" />
                                <p className="text-sm font-medium">Chưa Có Ảnh</p>
                                <p className="text-xs mt-1">Kết quả sẽ hiển thị ở đây</p>
                            </div>
                        )}
                    </div>
                  </div>
              </div>
            )}

            {/* OTHER TABS */}
            {activeTab === 'remove_bg' && <div className="h-full overflow-y-auto p-4 md:p-8 custom-scrollbar"><BackgroundRemover /></div>}
            {activeTab === 'ad_creator' && <div className="h-full custom-scrollbar"><AdCreator /></div>}
            {activeTab === 'content_genius' && <div className="h-full custom-scrollbar"><ContentGeniusAI /></div>}
            {activeTab === 'text_to_speech' && <div className="h-full overflow-y-auto p-4 md:p-8 custom-scrollbar"><TextToSpeech /></div>}
            {activeTab === 'prompt_builder' && <div className="h-full overflow-y-auto p-0 custom-scrollbar"><PromptBuilder /></div>}
            {activeTab === 'marketing_ai' && <div className="h-full custom-scrollbar"><MarketingAI /></div>}

        </div>
      </div>
    </div>
  );
};

export default App;
